sql:
SELECT p.project_name, r.genome_name, r.species
FROM projects p, reference_genomes r
WHERE p.project_name = 'Human Genome Assembly Project' AND r.species = 'Homo sapiens';

SELECT COUNT(method_id)
FROM assembly_methods
WHERE method_parameters LIKE '%k-mer size: 64%';

SELECT method_name
FROM assembly_methods
WHERE method_id = 1;

external_knowledge:
- "travelers" refers to the users;
- "embarked in the recent voyage through the digital ocean" means users who last logged in between January 1, 2023, and December 31, 2023;
- "charted their course using the scaffold-like stars" refers to users who have accessed an assembly method whose name includes "scaffold";
- "downloaded the treasure maps of completed voyages" refers to users who downloaded information from completed projects;
- "when did they set sail" refers to the date when the download occurred.

sql:
SELECT reference_genomes.genome_name, projects.project_name
FROM reference_genomes
JOIN projects ON reference_genomes.species = projects.project_name;
